// ---- Project: Full Implementation ----

// ---- Task Entity (Room) ----
@Entity(tableName = "tasks")
data class TaskEntity(
    @PrimaryKey(autoGenerate = true)
    val id: Int = 0,
    val title: String,
    val description: String,
    val projectId: Int? = null,
    val priority: String,
    val status: String,
    val dueDate: Long? = null,
    val createdAt: Long,
    val updatedAt: Long
) {
    fun toDomain(): Task {
        return Task(
            id = id,
            title = title,
            description = description,
            projectId = projectId,
            priority = Priority.valueOf(priority),
            status = TaskStatus.valueOf(status),
            dueDate = dueDate,
            createdAt = createdAt,
            updatedAt = updatedAt
        )
    }

    companion object {
        fun fromDomain(task: Task): TaskEntity {
            return TaskEntity(
                id = task.id,
                title = task.title,
                description = task.description,
                projectId = task.projectId,
                priority = task.priority.name,
                status = task.status.name,
                dueDate = task.dueDate,
                createdAt = task.createdAt,
                updatedAt = task.updatedAt
            )
        }
    }
}

// ---- Task DAO ----
@Dao
interface TaskDao {
    @Insert
    suspend fun insertTask(task: TaskEntity): Long

    @Update
    suspend fun updateTask(task: TaskEntity)

    @Delete
    suspend fun deleteTask(task: TaskEntity)

    @Query("SELECT * FROM tasks ORDER BY createdAt DESC")
    fun getAllTasks(): Flow<List<TaskEntity>>

    @Query("SELECT * FROM tasks WHERE id = :id")
    suspend fun getTaskById(id: Int): TaskEntity?

    @Query("SELECT * FROM tasks WHERE projectId = :projectId")
    fun getTasksByProject(projectId: Int): Flow<List<TaskEntity>>

    @Query("SELECT * FROM tasks WHERE status = :status")
    fun getTasksByStatus(status: String): Flow<List<TaskEntity>>

    @Query("DELETE FROM tasks WHERE id = :id")
    suspend fun deleteTaskById(id: Int)
}

// ---- Repository Implementation ----
class TaskRepositoryImpl(
    private val dao: TaskDao
) : TaskRepository {
    override fun getTasks(): Flow<List<Task>> {
        return dao.getAllTasks().map { entities ->
            entities.map { it.toDomain() }
        }
    }

    override fun getTasksByProject(projectId: Int): Flow<List<Task>> {
        return dao.getTasksByProject(projectId).map { entities ->
            entities.map { it.toDomain() }
        }
    }

    override suspend fun getTask(id: Int): Task? {
        return dao.getTaskById(id)?.toDomain()
    }

    override suspend fun saveTask(task: Task): Task {
        val entity = TaskEntity.fromDomain(task)
        val id = if (task.id == 0) {
            dao.insertTask(entity)
        } else {
            dao.updateTask(entity)
            task.id
        }
        return task.copy(id = id.toInt())
    }

    override suspend fun updateTask(task: Task): Task {
        dao.updateTask(TaskEntity.fromDomain(task))
        return task
    }

    override suspend fun deleteTask(id: Int) {
        dao.deleteTaskById(id)
    }
}

// ---- TaskListViewModel ----
@HiltViewModel
class TaskListViewModel @Inject constructor(
    private val getTasks: GetTasksUseCase,
    private val getTasksByStatus: GetTasksByStatusUseCase,
    private val deleteTask: DeleteTaskUseCase,
    private val completeTask: CompleteTaskUseCase
) : ViewModel() {

    data class UiState(
        val tasks: List<Task> = emptyList(),
        val filter: TaskStatus? = null,
        val isLoading: Boolean = false,
        val error: String? = null,
        val selectedTask: Task? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun loadTasks() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                getTasks().collect { tasks ->
                    val filtered = _uiState.value.filter?.let { filter ->
                        tasks.filter { it.status == filter }
                    } ?: tasks
                    _uiState.update {
                        it.copy(
                            tasks = tasks,
                            filteredTasks = filtered,
                            isLoading = false
                        )
                    }
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun setFilter(filter: TaskStatus?) {
        _uiState.update { state ->
            val filtered = filter?.let { f ->
                state.tasks.filter { it.status == f }
            } ?: state.tasks
            state.copy(filter = filter, filteredTasks = filtered)
        }
    }

    fun completeTask(id: Int) {
        viewModelScope.launch {
            try {
                completeTask(id)
                loadTasks()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message)
                }
            }
        }
    }

    fun deleteTask(id: Int) {
        viewModelScope.launch {
            try {
                deleteTask(id)
                loadTasks()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message)
                }
            }
        }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

